mapper.select:
SELECT *
FROM ship
WHERE corp_id = #{corpId}

    AND (
    name LIKE CONCAT('%', #{search}, '%')
    OR class_no LIKE CONCAT('%', #{search}, '%')
    OR imo LIKE CONCAT('%', #{search}, '%')
    )

ORDER BY create_date DESC
LIMIT #{limit} OFFSET #{offset}

mapper.delete:
DELETE FROM ship
WHERE ship_id = #{shipId}
  AND corp_id = #{corpId}
